package main

import (
    "encoding/json"
    "net/http"
    "time"
)

type HealthResponse struct {
    Status    string            `json:"status"`
    Version   string            `json:"version"`
    Timestamp string            `json:"timestamp"`
    Checks    map[string]string `json:"checks"`
}

func healthHandler(w http.ResponseWriter, r *http.Request) {
    checks := make(map[string]string)

    // Check database
    if err := checkDatabase(); err != nil {
        checks["database"] = "unhealthy: " + err.Error()
    } else {
        checks["database"] = "healthy"
    }

    // Check Redis
    if err := checkRedis(); err != nil {
        checks["redis"] = "unhealthy: " + err.Error()
    } else {
        checks["redis"] = "healthy"
    }

    // Determine overall status
    status := "healthy"
    statusCode := http.StatusOK
    for _, v := range checks {
        if v != "healthy" {
            status = "unhealthy"
            statusCode = http.StatusServiceUnavailable
            break
        }
    }

    response := HealthResponse{
        Status:    status,
        Version:   "1.0.0",
        Timestamp: time.Now().UTC().Format(time.RFC3339),
        Checks:    checks,
    }

    w.Header().Set("Content-Type", "application/json")
    w.WriteHeader(statusCode)
    json.NewEncoder(w).Encode(response)
}

from fastapi import FastAPI, Response
from datetime import datetime
import asyncio

app = FastAPI()

async def check_database():
    try:
        await db.execute("SELECT 1")
        return True, None
    except Exception as e:
        return False, str(e)

async def check_redis():
    try:
        await redis.ping()
        return True, None
    except Exception as e:
        return False, str(e)

@app.get("/health")
async def health_check(response: Response):
    checks = {}

    # Run checks in parallel
    db_ok, db_err = await check_database()
    redis_ok, redis_err = await check_redis()

    checks["database"] = "healthy" if db_ok else f"unhealthy: {db_err}"
    checks["redis"] = "healthy" if redis_ok else f"unhealthy: {redis_err}"

    all_healthy = db_ok and redis_ok

    if not all_healthy:
        response.status_code = 503

    return {
        "status": "healthy" if all_healthy else "unhealthy",
        "version": "1.0.0",
        "timestamp": datetime.utcnow().isoformat(),
        "checks": checks
    }

# Separate liveness and readiness
@app.get("/healthz")
async def liveness():
    """Liveness probe - is the process running?"""
    return {"status": "alive"}

@app.get("/readyz")
async def readiness(response: Response):
    """Readiness probe - can we serve traffic?"""
    db_ok, _ = await check_database()
    if not db_ok:
        response.status_code = 503
        return {"status": "not ready"}
    return {"status": "ready"}

const express = require('express');
const app = express();

async function checkDatabase() {
  try {
    await db.query('SELECT 1');
    return { healthy: true };
  } catch (error) {
    return { healthy: false, error: error.message };
  }
}

async function checkRedis() {
  try {
    await redis.ping();
    return { healthy: true };
  } catch (error) {
    return { healthy: false, error: error.message };
  }
}

app.get('/health', async (req, res) => {
  const [dbCheck, redisCheck] = await Promise.all([
    checkDatabase(),
    checkRedis()
  ]);

  const checks = {
    database: dbCheck.healthy ? 'healthy' : `unhealthy: ${dbCheck.error}`,
    redis: redisCheck.healthy ? 'healthy' : `unhealthy: ${redisCheck.error}`
  };

  const allHealthy = dbCheck.healthy && redisCheck.healthy;

  res.status(allHealthy ? 200 : 503).json({
    status: allHealthy ? 'healthy' : 'unhealthy',
    version: process.env.APP_VERSION || '1.0.0',
    timestamp: new Date().toISOString(),
    checks
  });
});
